class Solution(object):
    def minNumberOfHours(self, initialEnergy, initialExperience, energy, experience):
        exp_hours = 0
        for opp_exp in experience:
            if initialExperience <= opp_exp:
                exp_hours += opp_exp - initialExperience + 1
                initialExperience = opp_exp + 1
            initialExperience += opp_exp
        energy_hours = 0
        for opp_energy in energy:
            if initialEnergy <= opp_energy:
                energy_hours += opp_energy - initialEnergy + 1
                initialEnergy = opp_energy + 1
            initialEnergy -= opp_energy
        return exp_hours + energy_hours
